#include <bits/stdc++.h>
using namespace std;

int equalPairs(vector<vector<int>>& mat) {
    int ans = 0;
    map<vector<int>, int> mp;

    for (int i = 0; i < mat.size(); i++)
        mp[mat[i]]++;

    for (int i = 0; i < mat[0].size(); i++) {
        vector<int> v;
        for (int j = 0; j < mat.size(); j++)
            v.push_back(mat[j][i]);
        ans += mp[v];
    }

    return ans;
}


int main() {
  int n, m;
  cin >> n;

  assert(1 <= n && n <= 100);

  vector<vector<int> > mat(n, vector<int> (n));
  for(int i = 0; i < n; i++){
    for(int j = 0; j < n; j++){
        cin >> mat[i][j];
    }
  } 

  cout << equalPairs(mat);


  return 0;
}

