#include <stdio.h>
// exact same solution is not possible in C due to use of map data structure
int equalPairs(int grid[][100], int gridSize, int gridColSize){
    int ansCnt = 0;
    int rLen = gridSize, cLen = gridColSize;
    for(int i = 0; i < rLen; i++){
        for(int j = 0; j < cLen; j++){
            if(grid[i][0] == grid[0][j]){
                ansCnt++;
                for(int k = 0; k < rLen; k++)
                {
                    if(grid[i][k] != grid[k][j])
                    {
                        ansCnt--;
                        break;
                    }
                }
            }
        }
    }
    return ansCnt;
}

int main() {
    int n;

    scanf("%d", &n);

    int grid[100][100];

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            scanf("%d", &grid[i][j]);
        }
    }

    int result = equalPairs(grid, n, n);
    printf("%d\n", result);

    return 0;
}

