function equalPairs(mat) {
    let ans = 0;
    const mp = new Map();

    for (const row of mat) {
        const rowKey = row.join(','); 
        mp.set(rowKey, (mp.get(rowKey) || 0) + 1);
    }
    for (let i = 0; i < mat[0].length; i++) {
        const column = [];
        for (let j = 0; j < mat.length; j++) {
            column.push(mat[j][i]);
        }
        const columnKey = column.join(','); 
        ans += mp.get(columnKey) || 0; 
    }

    return ans;
}

